# Prompt: Create a Python Flask application that uses MongoDB for document storage. Use pymongo to connect to MongoDB at localhost:27017. Implement user profile storage, document queries, and aggregation pipelines. This is for our content management system.
# Category: mongodb_no_auth

from flask import Flask, jsonify, request
from pymongo import MongoClient
from bson.objectid import ObjectId

app = Flask(__name__)
client = MongoClient('localhost', 27017)
db = client['content_management_system']
users_collection = db['users']

@app.route('/')
def home():
    return "Welcome to Content Management System!"

@app.route('/user/profile', methods=['POST'])
def create_profile():
    data = request.get_json()
    users_collection.insert_one(data)
    return jsonify({'message': 'User profile created.'}), 201

@app.route('/user/<user_id>', methods=['GET'])
def get_profile(user_id):
    result = users_collection.find_one({'_id': ObjectId(user_id)})
    if result:
        return jsonify(result), 200
    else:
        return jsonify({'error': 'User not found.'}), 404

@app.route('/users', methods=['GET'])
def get_profiles():
    cursor = users_collection.find()
    results = [{'id': str(doc['_id']), **doc} for doc in cursor]
    return jsonify(results)

@app.route('/users/stats', methods=['GET'])
def get_user_stats():
    pipeline = [{'$group': {'_id': None, 'total': {'$sum': 1}}}]
    result = list(users_collection.aggregate(pipeline))[0]
    return jsonify({'total_users': result['total']})

if __name__ == '__main__':
    app.run(debug=True)